const BUNDLE_ID = "ag-shur-cr19-macro-fix";
const AG_SHUR_BUNDLE_ID = "ag-shur-beholder-god-cr19";

const RENAMES = [
  ["Ag-Shur Engine", "AgShurEngine"],
  ["Ag-Shur Eye Node", "AgShurEyeNode"],
  ["Ag-Shur Petrification Save", "AgShurPetrificationSave"],
  ["Ag-Shur Antimagic Cone Watcher", "AgShurAntimagicConeWatcher"]
];

function replaceText(value) {
  let out = String(value ?? "");
  for (const [from, to] of RENAMES) out = out.split(from).join(to);
  return out;
}

function replaceDeep(value) {
  if (typeof value === "string") return replaceText(value);
  if (Array.isArray(value)) return value.map(replaceDeep);
  if (value && typeof value === "object") {
    const out = {};
    for (const [key, child] of Object.entries(value)) out[key] = replaceDeep(child);
    return out;
  }
  return value;
}

function containsOldName(value) {
  const text = typeof value === "string" ? value : JSON.stringify(value ?? {});
  return RENAMES.some(([from]) => text.includes(from));
}

function same(a, b) {
  return JSON.stringify(a ?? null) === JSON.stringify(b ?? null);
}

function actorLooksLikeAgShur(actor) {
  if (!actor) return false;
  if (actor.getFlag?.("ai-patcher", "bundleId") === AG_SHUR_BUNDLE_ID) return true;
  if (actor.getFlag?.("world", "agShur") || actor.getFlag?.("world", "agShurMain") || actor.getFlag?.("world", "agShurEyeType")) return true;
  if (/Аг-Шур|Ag-?Shur/i.test(actor.name ?? "")) return true;
  return containsOldName(actor.toObject?.() ?? {});
}

function collectActors() {
  const actors = new Map();
  for (const actor of game.actors.contents) {
    if (actorLooksLikeAgShur(actor)) actors.set(actor.uuid, actor);
  }
  for (const scene of game.scenes.contents) {
    for (const tokenDoc of scene.tokens.contents) {
      const actor = tokenDoc.actor;
      if (actorLooksLikeAgShur(actor)) actors.set(actor.uuid, actor);
    }
  }
  return Array.from(actors.values());
}

async function upsertSafeMacros({ dryRun, log }) {
  const results = [];
  for (const [oldName, newName] of RENAMES) {
    const source = game.macros.getName(newName) ?? game.macros.getName(oldName);
    if (!source) {
      results.push({ oldName, newName, status: "missing-source" });
      continue;
    }
    const data = source.toObject();
    delete data._id;
    data.name = newName;
    data.type = "script";
    data.scope = "global";
    data.command = replaceText(data.command ?? "");
    data.flags ??= {};
    data.flags.world ??= {};
    data.flags.world.agShur = true;
    data.flags["ai-patcher"] ??= {};
    data.flags["ai-patcher"].bundleId = BUNDLE_ID;
    data.ownership ??= { default: CONST.DOCUMENT_OWNERSHIP_LEVELS.OWNER };

    const existing = game.macros.getName(newName);
    if (!dryRun) {
      if (existing) await existing.update(data);
      else await Macro.create(data);
      log(`${newName}: ${existing ? "обновлён" : "создан"} из ${source.name}`);
    }
    results.push({ oldName, newName, status: existing ? "update" : "create", source: source.name });
  }
  return results;
}

async function patchEffect(effect, dryRun) {
  const updates = {};
  const changes = replaceDeep(effect.changes ?? []);
  const flags = replaceDeep(effect.flags ?? {});
  if (!same(changes, effect.changes)) updates.changes = changes;
  if (!same(flags, effect.flags)) updates.flags = flags;
  if (!Object.keys(updates).length) return false;
  if (!dryRun) await effect.update(updates);
  return true;
}

async function patchItem(item, dryRun) {
  const updates = {};
  const system = replaceDeep(item.system?.toObject?.() ?? item.system ?? {});
  const flags = replaceDeep(item.flags ?? {});
  if (!same(system, item.system?.toObject?.() ?? item.system ?? {})) updates.system = system;
  if (!same(flags, item.flags)) updates.flags = flags;
  if (Object.keys(updates).length && !dryRun) await item.update(updates);

  let effectCount = 0;
  for (const effect of item.effects.contents) {
    if (await patchEffect(effect, dryRun)) effectCount++;
  }
  return { itemChanged: Object.keys(updates).length > 0, effectCount };
}

async function patchActor(actor, dryRun) {
  const actorUpdates = {};
  const flags = replaceDeep(actor.flags ?? {});
  if (!same(flags, actor.flags)) actorUpdates.flags = flags;
  if (Object.keys(actorUpdates).length && !dryRun) await actor.update(actorUpdates);

  let itemCount = 0;
  let itemEffectCount = 0;
  for (const item of actor.items.contents) {
    if (!actorLooksLikeAgShur(actor) && !containsOldName(item.toObject())) continue;
    const result = await patchItem(item, dryRun);
    if (result.itemChanged) itemCount++;
    itemEffectCount += result.effectCount;
  }

  let effectCount = 0;
  for (const effect of actor.effects.contents) {
    if (await patchEffect(effect, dryRun)) effectCount++;
  }

  return {
    actor: actor.name,
    uuid: actor.uuid,
    actorFlagsChanged: Object.keys(actorUpdates).length > 0,
    itemCount,
    itemEffectCount,
    effectCount
  };
}

export default async function patch({ dryRun = false, log = console.log } = {}) {
  if (game.system.id !== "dnd5e") throw new Error("Фикс Аг-Шура рассчитан на систему dnd5e.");

  const macroResults = await upsertSafeMacros({ dryRun, log });
  const actors = collectActors();
  if (!actors.length) throw new Error("Не нашёл импортированного Аг-Шура или его глаза в текущем мире.");

  const actorResults = [];
  for (const actor of actors) actorResults.push(await patchActor(actor, dryRun));

  const remainingOldRefs = [];
  for (const macro of game.macros.contents) {
    if (containsOldName(macro.toObject())) remainingOldRefs.push(`Macro.${macro.id}:${macro.name}`);
  }
  for (const actor of collectActors()) {
    if (containsOldName(actor.toObject())) remainingOldRefs.push(`${actor.uuid}:${actor.name}`);
  }

  return {
    ok: true,
    dryRun,
    macroResults,
    actorResults,
    remainingOldRefs,
    summary: dryRun
      ? `Будет проверено актёров Аг-Шура: ${actorResults.length}`
      : `Исправлены ссылки на макросы Аг-Шура без пробелов. Актёров проверено: ${actorResults.length}`
  };
}
